scwin.retrieveCtrtSelpchItemInfoCb = function (rtnList) {
  if (rtnList != null) {
    if (rtnList[0] == "N/A") {
      //팝업에서 닫기버튼 클릭시
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "dcScCd", ds_sellInfo.getOriginalCellData(ds_sellInfo.getRowPosition(), "dcScCd"));
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "dcScNm", ds_sellInfo.getOriginalCellData(ds_sellInfo.getRowPosition(), "dcScNm"));
    } else {
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "dcScCd", rtnList[0]);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "dcScNm", rtnList[1]);
      //사용자편의를 위하여 데이터셋에 추가
      var sameYn = "N";
      for (i = 0; i < ds_dcScCd.getRowCount(); i++) {
        if (ds_dcScCd.getCellData(i, "dcScCd") == ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "dcScCd")) {
          sameYn = "Y";
          break;
        }
      }
      if (sameYn == "N") {
        ds_dcScCd.insertRow(ds_dcScCd.getRowCount());
        ds_dcScCd.setCellData(ds_dcScCd.getRowCount() - 1, "dcScCd", rtnList[0]);
        ds_dcScCd.setCellData(ds_dcScCd.getRowCount() - 1, "dcScNm", rtnList[1]);
      }
    }
  } else {
    ds_sellInfo.setCellData(ds.getRowPosition(), "dcScCd", "");
    ds_sellInfo.setCellData(ds.getRowPosition(), "dcScNm", "");
  }
  ;
  scwin.f_setValue();
};

//적용할증금액 계산하기
scwin.f_calAmt = function () {
  var transCargoClsCd = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "transCargoClsCd"); //운송화물구분코드
  var adptExchRt = Number(ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "adptExchRt")); //환율
  var crcCd = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "crcCd"); //통화코드
  var unitCd = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "unitCd"); //계약단위코드
  var sellUnitCd = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "sellUnitCd"); //매출단위코드
  //var minCondWt		= ds_sellInfo.getCellData(ds_sellInfo.RowPosition, "minCondWt");		//최소조건중량
  //var maxCondWt		= ds_sellInfo.NameValue(ds_sellInfo.RowPosition, "maxCondWt");		//최대조건중량
  var famtFratClsCd = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "famtFratClsCd"); //계약정액정률구분코드(FM:정액, FR:정률)
  var orgSellUpr = Number(ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "orgSellUpr")); //매출단가
  var wt = Number(ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "wt")); //적용중량
  var sellAmtFcrc = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "sellAmtFcrc"); //적용할증금액외화
  var scRt = Number(ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "scRt")); //할증율
  var scAmtAll = 0; //할증금액	
  var sellAmtAll = 0; //매출금액

  //컨테이너인 경우와 벌크인 경우 계산방법 다름
  if (transCargoClsCd == "B") {
    //벌크인 경우 
    //할증금액
    scAmtAll = Number(ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "scAmtAll"));

    //계약단위코드와 매출단위코드가 다른 경우 체크
    if (unitCd != sellUnitCd) wt = $c.gus.cfConvert2Weight($p, wt, sellUnitCd, unitCd);

    //정액/정률 체크
    if (famtFratClsCd == "FM") sellAmtAll = scAmtAll * wt;else if (famtFratClsCd == "FR") sellAmtAll = orgSellUpr * wt * scRt / 100;

    //데이터셋에 값세팅
    if (crcCd == "KRW") {
      sellAmtAll = sellAmtAll.toFixed(0);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmtAll", sellAmtAll);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmt", sellAmtAll);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmtFcrc", 0);
    } else {
      sellAmtAll = sellAmtAll.toFixed(2);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmtAll", sellAmtAll);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmt", (sellAmtAll * adptExchRt).toFixed(0));
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmtFcrc", sellAmtAll);
    }
  } else if (transCargoClsCd == "C") {
    //컨테이너인 경우, 수량으로 계산
    sellAmtAll = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "qty") * orgSellUpr;
    if (crcCd == "KRW") {
      sellAmtAll = sellAmtAll.toFixed(0);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmtAll", sellAmtAll);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmt", sellAmtAll);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmtFcrc", 0);
    } else {
      sellAmtAll = sellAmtAll.toFixed(2);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmtAll", sellAmtAll);
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmt", (sellAmtAll * adptExchRt).toFixed(0));
      ds_sellInfo.setCellData(ds_sellInfo.getRowPosition(), "sellAmtFcrc", sellAmtAll);
    }
  }
};

//할증금액 또는 할증율을 입력하면 edit불가 또는 가능하게 함
scwin.f_setEditByValue = function () {
  var scAmtFcrc = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "scAmtFcrc"); //할증금액
  var scRt = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "scRt"); //할증율
  if (scAmtFcrc > 0 && scRt == 0) {
    gr_sellInfo.setReadOnly("column", "scAmtAll", false);
    gr_sellInfo.setReadOnly("column", "scRt", true);
  } else if (scAmtFcrc == 0 && scRt > 0) {
    gr_sellInfo.setReadOnly("column", "scAmtAll", true);
    gr_sellInfo.setReadOnly("column", "scRt", false);
  } else {
    gr_sellInfo.setReadOnly("column", "scAmtAll", false);
    gr_sellInfo.setReadOnly("column", "scRt", false);
  }
};
scwin.sbm_retrieve_submitDone = function () {
  if (ds_sellInfo.getRowCount() > 0) {
    ed_ctrtClntNm.setValue(" " + ds_sellInfo.getCellData(0, "ctrtClntNm"));
    ed_ctrtNo.setValue(" " + ds_sellInfo.getCellData(0, "ctrtNo"));
    ed_bilgClntNm.setValue(" " + ds_sellInfo.getCellData(0, "bilgClntNm"));
    var odrNo = ds_sellInfo.getCellData(0, "odrNo");

    //f_setTabOrderInfo(ds_sellInfo.NameValue(1, "odrNo"));

    scwin.f_set("RETRIEVE");

    //famtFratClsCd, orgWt, orgSellUpr값 세팅
    for (i = 0; i < ds_sellInfo.getRowCount(); i++) {
      var famtFratClsCd = "";

      //정액정률구분 세팅		

      if (ds_sellInfo.getCellData(i, "scAmt") > 0 && ds_sellInfo.getCellData(i, "scRt") == 0) {
        ds_sellInfo.setCellData(i, "famtFratClsCd", "FM");
      } else if (ds_sellInfo.getCellData(i, "scAmt") == 0 && ds_sellInfo.getCellData(i, "scRt") > 0) {
        ds_sellInfo.setCellData(i, "famtFratClsCd", "FR");
      }

      //순수오더매출건만 해당
      if (ds_sellInfo.getCellData(i, "dcScCd") == "") {
        for (j = 0; j <= ds_sellInfo.getRowCount(); j++) {
          if (ds_sellInfo.getCellData(j, "dcScCd") != "" && ds_sellInfo.getCellData(i, "selpchItemCd") == ds_sellInfo.getCellData(j, "selpchItemCd") && ds_sellInfo.getCellData(i, "ctrtWrkPathSeq") == ds_sellInfo.getCellData(j, "ctrtWrkPathSeq") && ds_sellInfo.getCellData(i, "sellCommNo") == ds_sellInfo.getCellData(j, "sellCommNo") && ds_sellInfo.getCellData(i, "commSeq") == ds_sellInfo.getCellData(j, "commSeq") && ds_sellInfo.getCellData(i, "odrWrkPathSeq") == ds_sellInfo.getCellData(j, "odrWrkPathSeq")) {
            ds_sellInfo.setCellData(j, "orgWt", ds_sellInfo.getCellData(i, "wt"));
            ds_sellInfo.setCellData(j, "orgSellUpr", ds_sellInfo.getCellData(i, "sellUpr"));
          }
        }
      }
      ;
    }

    //후에 매출중량과 매출단가 가져올때 사용하기 위하여 ds_sellInfo를 ds_orgSellInfo로 copy해둠
    $c.gus.cfCopyDataSet($p, ds_sellInfo, ds_orgSellInfo, "copyHeader=yes");
    ds_sellInfo.removeAll();
    $c.gus.cfCopyDataSet($p, ds_orgSellInfo, ds_sellInfo, "copyHeader=yes");

    //요율항목 콤보 만들기
    scwin.f_createComboDS(ds_sellInfo, ds_selpchItemCd, "selpchItemCd", "selpchItemNm");

    //계약작업경로 콤보 만들기	
    scwin.f_createComboDS(ds_sellInfo, ds_ctrtWrkPathSeq, "ctrtWrkPathSeq", "ctrtWrkPathNm");
    acb_selpchItemNm.setSelectedIndex(0);
    acb_ctrtWrkPathNm.setSelectedIndex(0);

    //필터링하기
    scwin.f_filter();

    //취소,완료체크
    scwin.f_checkOdrStatus();
  } else {
    //$c.gus.cfAlertMsg("작업경로를 먼저 등록하신 후에 할인할증을 등록할 수 있습니다."); //@이(가) 존재하지 않습니다.
    //f_setTabOrderInfo("");
    scwin.f_set("INIT");

    //if(parent.tab_mxTab_page(2).style.visibility != "hidden") {
    //	ed_odrNo.focus();
    //}
  }
  totalRows.setValue(ds_sellInfo.getRowCount());
};

//계약요율에 있는 중량 그리드 콤보 그리기 
scwin.f_createComboCondWtGridByCtrt = async function () {
  ds_condWt.removeAll();
  if (ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "dcScCd") == scwin.wtDcScCd) {
    var commCdYn = "N";

    //계약시, 품명에 대한 계약요율을 입력한 경우(이런경우는 드물지만, 구현해둔 것임)
    for (i = 0; i <= ds_dcScInfo.getRowCount(); i++) {
      if (ds_dcScInfo.getCellData(i, "dcScSelpchItemCd") == scwin.wtDcScCd //중량할증인 경우
      && ds_dcScInfo.getCellData(i, "commCd") == ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "commCd") //계약할인할증품명코드와 오더할인할증의 상위품명코드가 같은 경우
      ) {
        var condWt = ds_dcScInfo.getCellData(i, "minCondWt") + "~" + ds_dcScInfo.getCellData(i, "maxCondWt");

        //중복하여 addrow되는 것을 막기 위함	
        var sameYn = "N";
        for (j = 0; j <= ds_condWt.getRowCount(); j++) {
          if (ds_condWt.getCellData(j, "commCd") == ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "commCd") && ds_condWt.getCellData(j, "condWt") == condWt) {
            sameYn = "Y";
            break;
          }
        }
        if (condWt != "" && sameYn == "N") {
          ds_condWt.insertRow(i);
          var adptExchRt = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "adptExchRt"); //환율
          ds_condWt.setCellData(ds_condWt.getRowPosition(), "odrSellSeq", "0"); // 오더매출순번
          ds_condWt.setCellData(ds_condWt.getRowPosition(), "commCd", ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "commCd")); // 품명코드
          ds_condWt.setCellData(ds_condWt.getRowPosition(), "unitCd", ds_dcScInfo.getCellData(i, "unitCd")); // 단위코드
          ds_condWt.setCellData(ds_condWt.getRowPosition(), "crcCd", ds_dcScInfo.getCellData(i, "crcCd")); // 통화코드
          ds_condWt.setCellData(ds_condWt.getRowPosition(), "condWt", condWt); // 최소/최대조건중량   

          //통화코드에 따른 할증금액 세팅
          if (ds_dcScInfo.getCellData(i, "crcCd") == "KRW") {
            //원화인 경우
            //ds_condWt.NameValue(ds_condWt.RowPosition, "scAmtAll")		= ds_dcScInfo.NameValue(i, "ctrtTrf");	// 통화코드에 따른 할증금액(원화,외화)
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "scAmt", ds_dcScInfo.getCellData(i, "ctrtTrf")); // 할증금액
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "scAmtFcrc", "0"); // 할증금액외화
          } else {
            //외화인 경우
            //ds_condWt.NameValue(ds_condWt.RowPosition, "scAmtAll")		= ds_dcScInfo.NameValue(i, "ctrtTrf");	// 통화코드에 따른 할증금액(원화,외화)
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "scAmt", (ds_dcScInfo.getCellData(i, "ctrtTrf") * adptExchRt).toFixed(0)); // 할증금액
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "scAmtFcrc", ds_dcScInfo.getCellData(i, "ctrtTrf")); // 할증금액외화
          }
          ds_condWt.setCellData(ds_condWt.getRowPosition(), "scRt", ds_dcScInfo.getCellData(i, "ctrtTrfRt")); // 할증률
          ds_condWt.setCellData(ds_condWt.getRowPosition(), "famtFratClsCd", ds_dcScInfo.getCellData(i, "famtFratClsCd")); // 정액정률구분코드
          commCdYn = "Y";
        }
      }
    }
    if (commCdYn == "N") {
      //계약시, 품목에 대한 계약요율을 입력한 경우
      for (i = 0; i <= ds_dcScInfo.getRowCount(); i++) {
        if (ds_dcScInfo.getCellData(i, "dcScSelpchItemCd") == scwin.wtDcScCd //중량할증인 경우
        && ds_dcScInfo.getCellData(i, "commCd") == ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "upperCommCd") //계약할인할증품명코드와 오더할인할증의 상위품명코드가 같은 경우
        ) {
          var condWt = ds_dcScInfo.getCellData(i, "minCondWt") + "~" + ds_dcScInfo.getCellData(i, "maxCondWt");

          //중복하여 addrow되는 것을 막기 위함	
          var sameYn = "N";
          for (j = 0; j <= ds_condWt.getRowCount(); j++) {
            if (ds_condWt.getCellData(j, "commCd") == ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "commCd") && ds_condWt.getCellData(j, "condWt") == condWt) {
              sameYn = "Y";
              break;
            }
          }
          if (condWt != "" && sameYn == "N") {
            ds_condWt.insertRow(i);
            var adptExchRt = ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "adptExchRt"); //환율
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "odrSellSeq", "0"); // 오더매출순번
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "commCd", ds_sellInfo.getCellData(ds_sellInfo.getRowPosition(), "commCd")); // 품명코드
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "unitCd", ds_dcScInfo.getCellData(i, "unitCd")); // 단위코드
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "crcCd", ds_dcScInfo.getCellData(i, "crcCd")); // 통화코드
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "condWt", condWt); // 최소/최대조건중량

            //통화코드에 따른 할증금액 세팅
            if (ds_dcScInfo.NameValue(i, "crcCd") == "KRW") {
              //원화인 경우
              //ds_condWt.NameValue(ds_condWt.RowPosition, "scAmtAll")		= ds_dcScInfo.NameValue(i, "ctrtTrf");	// 통화코드에 따른 할증금액(원화,외화)
              ds_condWt.setCellData(ds_condWt.getRowPosition(), "scAmt", ds_dcScInfo.getCellData(i, "ctrtTrf")); // 할증금액
              ds_condWt.setCellData(ds_condWt.getRowPosition(), "scAmtFcrc", 0); // 할증금액외화
            } else {
              //외화인 경우
              //ds_condWt.NameValue(ds_condWt.RowPosition, "scAmtAll")		= ds_dcScInfo.getCellData(i, "ctrtTrf");	// 통화코드에 따른 할증금액(원화,외화)
              ds_condWt.setCellData(ds_condWt.getRowPosition(), "scAmt", (ds_dcScInfo.getCellData(i, "ctrtTrf") * adptExchRt).toFixed(0)); // 할증금액
              ds_condWt.setCellData(ds_condWt.getRowPosition(), "scAmtFcrc", ds_dcScInfo.getCellData(i, "ctrtTrf")); // 할증금액외화
            }
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "scRt", ds_dcScInfo.getCellData(i, "ctrtTrfRt")); // 할증률
            ds_condWt.setCellData(ds_condWt.getRowPosition(), "famtFratClsCd", ds_dcScInfo.getCellData(i, "famtFratClsCd")); // 정액정률구분코드
          }
        }
      }
    }
  } else {
    ds_condWt.removeAll();
  }
};
